  return { pass: false, score: 0, reason: `bad trajectory: ${JSON.stringify(seq)}` };
return { pass: true, score: 1, reason: `order ok: ${JSON.stringify(seq)}` };

const m = context.metadata || {};
if (!m.terminated)
  return { pass: false, score: 0, reason: `did not terminate cleanly (next!=FINISH or no report)` };
return { pass: true, score: 1, reason: "terminated cleanly" };

