// Calibrated to real gpt-4o-mini runs: observed ~11.3k tokens/case (90,610 over 8).
// 20k ceiling = ~75% headroom for longer questions / a search loop, while still
// catching a genuine blowup (a looping/runaway agent hits 30k+).
const MAX_TOKENS = 20000;
if ((m.step_count || 0) > MAX_STEPS)
  return { pass: false, score: 0, reason: `step budget exceeded: ${m.step_count} > ${MAX_STEPS}` };
if ((m.total_tokens || 0) > MAX_TOKENS)
  return { pass: false, score: 0, reason: `token budget exceeded: ${m.total_tokens} > ${MAX_TOKENS}` };
return { pass: true, score: 1, reason: `steps=${m.step_count} tokens=${m.total_tokens}` };

